fun fibonacci(n: Int): Int {
    if (n <= 0) return 0
    if (n == 1) return 1

    var prev = 0
    var curr = 1
    repeat(n - 1) {
        val next = prev + curr
        prev = curr
        curr = next
    }
    return curr
}

# Recursive algorithm
def fibonacci_recursive(num):
    """ Calculate fibonacci number """
    if num == 0:
        return 0
    elif num in {1, 2}:
        return 1
    else:
        return fibonacci_recursive(num-1) + fibonacci_recursive(num - 2)

# Iterative algorithm
def fibonacci(num):
    """ Calculate fibonacci number (iterative function)"""
    nb1, nb2 = 0, 1

    for nbr in range(2 ,num+1):
        nb1, nb2 = nb2, nb1 + nb2

    return nb2

