func fibonacci(_ n: Int) -> Int {
    guard n != 0, n != 1 else { return n }
    return fibonacci(n - 1) + fibonacci(n - 2)
}

export function fibonacci(n) {
  if (n <= 1) {
    return n;
  }

  let previous = 0;
  let current = 1;
  for (let i = 2; i <= n; i += 1) {
    const next = previous + current;
    previous = current;
    current = next;
  }

  return current;
}

